run;

/* Derive USUBJID and RELRECSEQ */
proc sort data=relrec_raw;
  by STUDYID SUBJECTID;
run;

data relrec;
  set relrec_raw;
  by STUDYID SUBJECTID;

  /* Derive USUBJID: Format XX-XXX-XXXX */
  USUBJID = compress(STUDYID || '-' || SITEID || '-' || put(SUBJECTID, z4.));

  /* Derive RELRECSEQ: Sequential numbering per subject */
  if first.SUBJECTID then RELRECSEQ = 1;
  else RELRECSEQ + 1;

  /* Map RDOMAIN: Related Domain Abbreviation */
  RDOMAIN = DOMAIN1;

  /* Map IDVAR: Identifying Variable */
  IDVAR = DOMAIN1 || 'SEQ';

  /* Map IDVARVAL: Identifying Variable Value */
  IDVARVAL = put(SEQ1, 8.);

  /* Map RELTYPE: Relationship Type */
  /* Keep as is from raw data */

  /* Map RELID: Related Record Identifier */
  RELID = DOMAIN2 || '-' || put(SEQ2, 8.);

  /* Add DOMAIN: Fixed value for RELREC */
  DOMAIN = 'RELREC';

  drop SUBJECTID SITEID DOMAIN1 SEQ1 DOMAIN2 SEQ2;
run;

/* Apply variable attributes per SDTM specification */
data sdtm.relrec(label='Related Records');
  attrib
    STUDYID   label='Study Identifier'            length=$12
    DOMAIN    label='Domain Abbreviation'         length=$2
    USUBJID   label='Unique Subject Identifier'   length=$11
    RELRECSEQ label='Sequence Number'             length=8
    RDOMAIN   label='Related Domain Abbreviation' length=$2
    IDVAR     label='Identifying Variable'        length=$8
    IDVARVAL  label='Identifying Variable Value'  length=$8
    RELTYPE   label='Relationship Type'           length=$6
    RELID     label='Related Record Identifier'   length=$16
  ;
  set relrec;
run;

/* Create a permanent SAS dataset with xport format */
libname xptout xport "/path/to/output/relrec.xpt";
proc copy in=sdtm out=xptout;
  select relrec;
run;
libname xptout clear;
